code.bash:
# 基本函数定义
greet() {
    echo "Hello, $1!"
}
greet "World"  # Hello, World!

# 多参数函数
add() {
    echo $(($1 + $2))
}
result=$(add 5 3)
echo "结果: $result"  # 8

# 返回状态码
check_file() {
    if [ -f "$1" ]; then
        return 0  # 成功
    else
        return 1  # 失败
    fi
}

if check_file "/etc/passwd"; then
    echo "文件存在"
fi

# 局部变量
counter() {
    local count=0  # 局部变量
    ((count++))
    echo $count
}

# 数组参数
print_args() {
    for arg in "$@"; do
        echo "$arg"
    done
}
print_args a b c

# 返回多个值
get_info() {
    echo "Alice"
    echo "25"
}
read name age <<< $(get_info)

# 递归函数
factorial() {
    if [ $1 -le 1 ]; then
        echo 1
    else
        local prev=$(factorial $(($1 - 1)))
        echo $(($1 * prev))
    fi
}
echo $(factorial 5)  # 120

